/**
 * noticeAssets — OwnerPilot brand marks for generated notices, inlined as
 * base64 data URIs so they render in print windows and preview iframes with
 * NO asset-path or network dependency (and no async image-load race before
 * the print dialog fires). Source PNGs have transparent backgrounds.
 *
 *  - LETTERHEAD_DATA_URI: full mark + "OwnerPilot.AI" wordmark (page-1 letterhead).
 *  - MARK_DATA_URI: house mark only (page footers).
 *
 * Regenerate from the source PNGs in /public if the brand changes.
 */

export const LETTERHEAD_DATA_URI =
  'data:image/png;base64,';

export const MARK_DATA_URI =
  'data:image/png;base64,';
